module.render:
const esc = (s) => String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const color = args.color || 'var(--accent-color)';
const pts = String(args.points || '12,85 88,85 62,15').trim().split(/\s+/).map((p) => p.split(',').map(parseFloat)).filter((p) => p.length === 2 && p.every(Number.isFinite));
if (pts.length !== 3) return `<div>(triangle: points must be three "x,y" pairs)</div>`;
const labels = String(args.labels || 'A,B,C').split(',').map((s) => s.trim());
const sideLabels = String(args.sides || '').split(',').map((s) => s.trim());
const marks = String(args.marks || '').split(',').map((s) => s.trim()).filter(Boolean);
const cx = (pts[0][0] + pts[1][0] + pts[2][0]) / 3, cy = (pts[0][1] + pts[1][1] + pts[2][1]) / 3;
const away = (p, d) => { const dx = p[0] - cx, dy = p[1] - cy, L = Math.hypot(dx, dy) || 1; return [p[0] + dx / L * d, p[1] + dy / L * d]; };
const toward = (p, d) => away(p, -d);
let svg = `<polygon points="${pts.map((p) => p.join(',')).join(' ')}" class="mdp-tr-shape"/>`;
// side labels: midpoint pushed outward
for (let i = 0; i < 3; i++) {
  const lbl = sideLabels[i];
  if (!lbl) continue;
  const a = pts[i], b = pts[(i + 1) % 3];
  const m = away([(a[0] + b[0]) / 2, (a[1] + b[1]) / 2], 7);
  svg += `<text x="${m[0].toFixed(1)}" y="${m[1].toFixed(1)}" class="mdp-tr-side" text-anchor="middle" dominant-baseline="middle"><tspan font-style="italic">${esc(lbl)}</tspan></text>`;
}
// vertex labels + angle marks
for (let i = 0; i < 3; i++) {
  const p = pts[i];
  const o = away(p, 8);
  if (labels[i]) svg += `<text x="${o[0].toFixed(1)}" y="${o[1].toFixed(1)}" class="mdp-tr-vertex" text-anchor="middle" dominant-baseline="middle">${esc(labels[i])}</text>`;
  const prev = pts[(i + 2) % 3], next = pts[(i + 1) % 3];
  const u = (q) => { const dx = q[0] - p[0], dy = q[1] - p[1], L = Math.hypot(dx, dy) || 1; return [dx / L, dy / L]; };
  const u1 = u(prev), u2 = u(next);
  if (String(args.right || '').trim() === labels[i]) {
    const k = 8;
    const c1 = [p[0] + u1[0] * k, p[1] + u1[1] * k], c2 = [p[0] + u2[0] * k, p[1] + u2[1] * k];
    const c3 = [p[0] + (u1[0] + u2[0]) * k, p[1] + (u1[1] + u2[1]) * k];
    svg += `<polyline points="${c1[0].toFixed(1)},${c1[1].toFixed(1)} ${c3[0].toFixed(1)},${c3[1].toFixed(1)} ${c2[0].toFixed(1)},${c2[1].toFixed(1)}" class="mdp-tr-right"/>`;
  } else if (marks.includes(labels[i])) {
    const r = 10;
    const a1 = [p[0] + u1[0] * r, p[1] + u1[1] * r], a2 = [p[0] + u2[0] * r, p[1] + u2[1] * r];
    const cross = u1[0] * u2[1] - u1[1] * u2[0];
    svg += `<path d="M${a1[0].toFixed(1)},${a1[1].toFixed(1)} A${r},${r} 0 0 ${cross > 0 ? 1 : 0} ${a2[0].toFixed(1)},${a2[1].toFixed(1)}" class="mdp-tr-arc"/>`;
  }
}
const fill = String(args.fill) !== 'false';
const strokeW = (args.strokewidth || '1.2').trim() || '1.2';
const maxW = (args.maxwidth || '340px').trim() || '340px';
const cls = 'mdp-mod-triangle' + (fill ? '' : ' mdp-tr-nofill');
return `\n\n<div class="${cls}" style="--tr-c:${color}; --tr-sw:${strokeW}; --tr-mw:${maxW};"><svg viewBox="-6 -6 112 112" preserveAspectRatio="xMidYMid meet">${svg}</svg></div>\n\n`;
